    92â†’		opts.GroupWait = time.Duration(*cr.GroupWait)
    93â†’	}
    94â†’	if cr.GroupInterval != nil {
    95â†’		opts.GroupInterval = time.Duration(*cr.GroupInterval)
    96â†’	}
    97â†’	if cr.RepeatInterval != nil {
    98â†’		opts.RepeatInterval = time.Duration(*cr.RepeatInterval)
    99â†’	}
   100â†’
   101â†’	// Build matchers.
