   158â†’// Match does a depth-first left-to-right search through the route tree
   159â†’// and returns the matching routing nodes.
   160â†’func (r *Route) Match(lset model.LabelSet) []*Route {
   161â†’	if !r.Matchers.Matches(lset) {
   162â†’		return nil
   163â†’	}
