   165â†’	var all []*Route
   166â†’
   167â†’	for _, cr := range r.Routes {
   168â†’		matches := cr.Match(lset)
   169â†’
   170â†’		all = append(all, matches...)
   171â†’
   172â†’		if matches != nil && !cr.Continue {
   173â†’			break
   174â†’		}
