   229â†’// RouteOpts holds various routing options necessary for processing alerts
   230â†’// that match a given route.
   231â†’type RouteOpts struct {
   232â†’	// The identifier of the associated notification configuration.
   233â†’	Receiver string
   234â†’
   235â†’	// What labels to group alerts by for notifications.
   236â†’	GroupBy map[model.LabelName]struct{}
