   243â†’	GroupWait      time.Duration
   244â†’	GroupInterval  time.Duration
   245â†’	RepeatInterval time.Duration
   246â†’
   247â†’	// A list of time intervals for which the route is muted.
   248â†’	MuteTimeIntervals []string
